const items = $input.all();
return items.map(item => {
  const d = item.json;
  if (!d.exists && !d.contact) {
    return { json: { encontrado: false, mensagem: 'Contato não encontrado no CRM' } };
  }
  const c = d.contact || d;
  const deals = c.deals || [];
  const openDeals = deals.filter(dl => dl.status === 'open');
  return {
    json: {
      encontrado: true,
      contact_id: c.id,
      nome: c.name,
      email: c.email,
      phone: c.phone,
      role: c.role,
      company_id: c.company_id,
      company_name: c.company ? c.company.name : null,
      deals_abertos: openDeals.length,
      deals: openDeals.map(dl => ({ deal_id: dl.id, title: dl.title, pipeline_name: dl.pipeline_name, stage: dl.stage_name, temperature: dl.temperature, value: dl.value }))
    }
  };
});
